            body.put("authenticated", SecurityContextHolder.getContext().getAuthentication() != null && SecurityContextHolder.getContext().getAuthentication().isAuthenticated());
            body.put("user", session.getUsername());
            body.put("subject", session.getSubject());
            body.put("email", session.getEmail());
            body.put("claims", session.getClaims());
